import { useState, useEffect } from 'react';
import fire from "../fire"
import Alert from '@material-ui/lab/Alert';
import Cards from './Cards';
import { makeStyles } from '@material-ui/core/styles';
import SearchIcon from '@material-ui/icons/Search';
import TableChartIcon from '@material-ui/icons/TableChart';
import EqualizerIcon from '@material-ui/icons/Equalizer';
import { Button, Grid, TextField, IconButton, Select, FormControl, MenuItem, InputLabel } from '@material-ui/core';
const useStyles = makeStyles((theme) => ({
    margin: {
        margin: theme.spacing(1),
    },
    button: {
        margin: theme.spacing(1),
    },
    formControl: {
        margin: theme.spacing(1),
        minWidth: 120,
    },
    selectEmpty: {
        marginTop: theme.spacing(2),
    },
}));



const Search = () => {

    const classes = useStyles();


    const [data, setData] = useState(null);
    const [asin, setAsin] = useState('');
    const [country, setCountry] = useState('AU');
    const [top, setTop] = useState('0');
    const [url, setUrl] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');






    useEffect(() => {
        const fetchData = () => {
            setIsLoading(true);
            fetch(url).then(res => {
                return res.json();
            })
                .then(data => {


                    if (!data.status) {
                        setData(data);
                        setError(false);
                        setIsLoading(false);
                    } else {
                        setError(true);
                        setErrorMessage(data.message)
                        setIsLoading(false);
                    }
                })
                .catch(error => {

                    console.log(error)
                })
        }

        if (url !== '') {
            setData(null)
            fetchData();
            setUrl('');
        }



    }, [url, data]);


    const handleAsin = (event) => {
        setAsin(event.target.value)
    }
    const handleCountry = (event) => { setCountry(event.target.value) }
    const handleTop = (event) => { setTop(event.target.value) }
    const handleLogout = () => { fire.auth().signOut() }


    const clickSearch = () => {


        if (url !== '') {
            var url = 'http://localhost:5000/api/reviewProduct?asin=' + asin + '&country=' + country + '&top=' + top;
            // var url = 'http://localhost:5000/api/test'
            setUrl(url)
        }
    }



    return (

        <div>
            <Button onClick={handleLogout}>Logout</Button>
            <div className={classes.margin}>
                <Grid container spacing={1} alignItems="flex-end">

                    <Grid item>
                        <TextField value={keywords} onChange={handleKeywords} id="input-with-icon-grid" label="Search..." />
                    </Grid>
                    <Grid item>
                        <FormControl className={classes.formControl}>
                            <InputLabel id="demo-simple-select-label">Country</InputLabel>
                            <Select
                                labelId="demo-simple-select-label"
                                id="demo-simple-select"
                                value={country}
                                onChange={handleCountry}
                            >
                                <MenuItem value={"US"}>United States</MenuItem>
                                <MenuItem value={"AU"}>Australia</MenuItem>
                                <MenuItem value={"GB"}>Great Britain</MenuItem>
                                <MenuItem value={"FR"}>France</MenuItem>
                            </Select>
                        </FormControl>
                    </Grid>

                    <Grid item>
                        <IconButton disabled={!keywords} onClick={clickSearch}>
                            <SearchIcon></SearchIcon>
                        </IconButton>
                    </Grid>
                </Grid>
            </div>
            <label>
                Search:
            <input type="text" value={asin} onChange={handleAsin} />
            </label>
            <select value={country} onChange={handleCountry}>
                <option defaultValue value="US">United States</option>
                <option value="AU">Australia</option>
                <option value="GB">Great Britain</option>
                <option value="FR">France</option>
            </select>
            <select value={top} onChange={handleTop}>
                <option defaultValue value="0">Most Recent</option>
                <option value="1">Top Reviews</option>
            </select>
            {error && <Alert variant="outlined" severity="error" onClose={() => { setError(false) }}>{errorMessage}</Alert>}
            <button disabled={!asin} type="button" onClick={clickSearch}>
                Search
            </button>



            {isLoading && <div>Loading...</div>}
            {data && <Cards data={data} />}



        </div>

    );
}

export default Search;
